// Replays flutter/test/goldens/coach_goldens.json, generated by executing
// the REAL RN coach.js. Every candidate kind, ranking, exact message string
// (peso formatting included), check-in choice, and win branch must match.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/coach.dart';

dynamic normalize(dynamic v) {
  if (v is num) return v.toDouble();
  if (v is Map) return v.map((k, x) => MapEntry(k.toString(), normalize(x)));
  if (v is List) return v.map(normalize).toList();
  return v;
}

void main() {
  final raw = jsonDecode(
      File('test/goldens/coach_goldens.json').readAsStringSync())
      as Map<String, dynamic>;
  final ref = DateTime(2026, 7, 16, 12);
  final nov = DateTime(2026, 11, 16, 12);

  test('weekKey matches', () {
    expect(weekKey(ref), raw['weekKey']);
  });

  for (final entry in (raw['scenarios'] as Map<String, dynamic>).entries) {
    test('coach golden: ${entry.key}', () {
      final s = entry.value as Map<String, dynamic>;
      final data = (s['data'] as Map).cast<String, dynamic>();
      final r = entry.key == 'kitchenSinkNov' ? nov : ref;
      expect(normalize(decisionCandidates(data, r)),
          normalize(s['candidates']),
          reason: '${entry.key} candidates');
      expect(normalize(weeklyCheckIn(data, r)), normalize(s['checkIn']),
          reason: '${entry.key} checkIn');
      expect(normalize(pickWin(data, r)), normalize(s['win']),
          reason: '${entry.key} win');
    });
  }
}
